export class RetryPolicy {
  execute<T>(fn: () => T, retries: number): T {
    let attempts = 0;
    while (true) {
      try {
        return fn();
      } catch (err) {
        attempts++;
        if (attempts > retries) {
          throw err;
        }
      }
    }
  }
}

tests:
import { RetryPolicy } from "./source";

test("returns successful result", () => {
  const policy = new RetryPolicy();
  expect(policy.execute(() => 42, 2)).toBe(42);
});

test("retries before succeeding", () => {
  const policy = new RetryPolicy();
  let calls = 0;
  const result = policy.execute(() => {
    calls++;
    if (calls < 3) throw new Error("fail");
    return "ok";
  }, 3);
  expect(result).toBe("ok");
  expect(calls).toBe(3);
});

test("throws after max retries", () => {
  const policy = new RetryPolicy();
  expect(() => policy.execute(() => { throw new Error("boom"); }, 1)).toThrow("boom");
});

