public class PasswordPolicy
{
    public bool IsValid(string password)
    {
        if (password.Length < 8) return false;
        bool hasDigit = false;
        foreach (char c in password)
        {
            if (char.IsDigit(c))
            {
                hasDigit = true;
            }
        }
        return hasDigit;
    }
}

