func TestEmpty(t *testing.T) {
    _, err := Process("")
    if err == nil || err.Error() != "empty input" {
        t.Fatal("expected empty input error")
    }
}

func TestTooLong(t *testing.T) {
    long := make([]byte, 101)
    for i := range long { long[i] = 'a' }
    _, err := Process(string(long))
    if err == nil || err.Error() != "input too long" {
        t.Fatal("expected too long error")
    }
}

func TestOK(t *testing.T) {
    result, err := Process("hello")
    if err != nil || result != "hello_ok" {
        t.Fatalf("expected hello_ok, got %s", result)
    }
}

