public class Invoicer
{
    public decimal Calculate(decimal price, int quantity, decimal discount)
    {
        if (price < 0) throw new ArgumentException("negative price");
        if (quantity <= 0) throw new ArgumentException("non-positive quantity");
        if (discount < 0 || discount > 1) throw new ArgumentException("invalid discount");
        return price * quantity * (1 - discount);
    }
}

tests:
using Xunit;

public class InvoicerTests
{
    [Fact] public void NegativePrice() => Assert.Throws<ArgumentException>(() => new Invoicer().Calculate(-1, 1, 0));
    [Fact] public void ZeroQty() => Assert.Throws<ArgumentException>(() => new Invoicer().Calculate(10, 0, 0));
    [Fact] public void BadDiscount() => Assert.Throws<ArgumentException>(() => new Invoicer().Calculate(10, 1, 1.5m));
    [Fact] public void Normal() => Assert.Equal(90m, new Invoicer().Calculate(10m, 10, 0.1m));
}

